mapper.select:
SELECT dc.id, dc.document_id, dc.chunk_index, dc.content, dv.embedding, dc.created_at,
       dv.embedding <-> CAST(#{queryVector} AS vector) AS distance
FROM document_chunk dc
LEFT JOIN document_chunk_vector dv ON dc.id = dv.id
LEFT JOIN documents d ON dc.document_id = d.id


        d.knowledge_base_id = #{knowledgeBaseId, typeHandler=com.example.rag.config.UUIDTypeHandler}


        AND dc.document_id = #{documentId, typeHandler=com.example.rag.config.UUIDTypeHandler}


ORDER BY distance
LIMIT #{limit}

SELECT dc.id, dc.document_id, dc.chunk_index, dc.content, dv.embedding, dc.created_at,
       dv.embedding <#> CAST(#{queryVector} AS vector) AS distance
FROM document_chunk dc
LEFT JOIN document_chunk_vector dv ON dc.id = dv.id
LEFT JOIN documents d ON dc.document_id = d.id


        d.knowledge_base_id = #{knowledgeBaseId, typeHandler=com.example.rag.config.UUIDTypeHandler}


        AND dc.document_id = #{documentId, typeHandler=com.example.rag.config.UUIDTypeHandler}


ORDER BY distance
LIMIT #{limit}

SELECT dc.id, dc.document_id, dc.chunk_index, dc.content, dv.embedding, dc.created_at,
       1 - (dv.embedding <=> CAST(#{queryVector} AS vector)) AS similarity
FROM document_chunk dc
LEFT JOIN document_chunk_vector dv ON dc.id = dv.id
LEFT JOIN documents d ON dc.document_id = d.id


        d.knowledge_base_id = #{knowledgeBaseId, typeHandler=com.example.rag.config.UUIDTypeHandler}


        AND dc.document_id = #{documentId, typeHandler=com.example.rag.config.UUIDTypeHandler}


ORDER BY similarity DESC
LIMIT #{limit}

SELECT dc.id, dc.document_id, dc.chunk_index, dc.content, dv.embedding, dc.created_at,
       dv.embedding <@> CAST(#{queryVector} AS vector) AS distance
FROM document_chunk dc
LEFT JOIN document_chunk_vector dv ON dc.id = dv.id
LEFT JOIN documents d ON dc.document_id = d.id


        d.knowledge_base_id = #{knowledgeBaseId, typeHandler=com.example.rag.config.UUIDTypeHandler}


        AND dc.document_id = #{documentId, typeHandler=com.example.rag.config.UUIDTypeHandler}


ORDER BY distance
LIMIT #{limit}
